# scripts/infer-gate-tier.py
import sys, yaml, subprocess, re

def parse_version(v: str) -> tuple:
    return tuple(int(x) for x in v.split("."))

def infer_tier(old_version: str, new_version: str) -> str:
    old = parse_version(old_version)
    new = parse_version(new_version)
    if new[0] > old[0]:
        return "major"
    if new[1] > old[1]:
        return "minor"
    if new[2] > old[2]:
        return "patch"
    raise ValueError(f"Version did not increase: {old_version} -> {new_version}")

TIER_GATES = {
    "patch": ["gate-1-schema"],
    "minor": ["gate-1-schema", "gate-2-injection", "gate-3-regression"],
    "major": ["gate-1-schema", "gate-2-injection", "gate-3-regression", "gate-4-human"],
}

# In CI: write required gates to GITHUB_OUTPUT for conditional job steps
if __name__ == "__main__":
    old_ver, new_ver = sys.argv[1], sys.argv[2]
    tier = infer_tier(old_ver, new_ver)
    gates = TIER_GATES[tier]
